import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

// In Flowise chatflow configuration
const chatflowConfig = {
  // ... other config
  callbacks: {
    onChatFlowExecution: async (data) => {
      const span = await vex.span('hr-screening-flow', {
        input: { resume: data.input, jobReq: data.jobDescription },
        tags: { regulation: 'EEOC', useCase: 'resume-screening' }
      });

      // Validate output for bias
      if (data.output.includes('cultural fit') || data.output.match(/age|gender/i)) {
        span.fail('potential bias detected');
        throw new Error('Compliance violation');
      }

      await span.success({ score: data.candidateScore });
    }
  }
};

vex.span('vector-retrieval', async (span) => {
  const query = 'software engineer with Python experience';
  const docs = await vectorStore.similaritySearch(query, 5);

  for (const doc of docs) {
    span.event('doc-retrieved', {
      content: doc.pageContent.slice(0, 200),
      score: doc.metadata.similarityScore,
      protectedTerms: doc.pageContent.match(/(disability|age|veteran|gender)/gi) || []
    });

    if (doc.metadata.similarityScore < 0.7) {
      span.fail('low relevance retrieval');
      return []; // Block low-relevance docs
    }

    if (doc.pageContent.match(/(disability|age|veteran)/i)) {
      span.fail('protected characteristic in retrieval');
    }
  }

  return docs;
});

// Sequential agent handoff monitoring
const agents = ['screener', 'skills-extractor', 'interviewer'];

for (let i = 0; i < agents.length; i++) {
  const span = await vex.span(`hr-agent-${agents[i]}`, {
    input: agentInputs[i],
    prevContext: i > 0 ? agentOutputs[i-1] : null,
    tags: { handoffIndex: i, regulation: 'NYC-LL144' }
  });

  const output = await agents[i].execute(agentInputs[i]);

  // Validate context preservation
  if (i > 0 && !output.context.includes('fairness-checked')) {
    span.fail('context loss between agents');
    throw new Error('Fairness context missing');
  }

  // Check for bias drift
  const biasScore = analyzeBias(output);
  if (biasScore > 0.3) {
    span.fail(`bias drift detected: ${biasScore}`);
  }

  agentOutputs[i] = output;
  await span.success({ biasScore });
}
